mapper.insert:
INSERT
INTO BIF.TB_BATCH_LOG (
		NPID,
		SIF_ID,
		SSYS_NM,
		STB_NM,
		DSTART_DT,
		SSTEP_STATUS,
		SCOMMENT,
		SBATCH_END_YN,
		DCREATE_DT,
		DMODIFY_DT
) VALUES (
	#{npid, jdbcType=BIGINT}
	,	#{sifId, jdbcType=VARCHAR}
	,	#{ssysNm, jdbcType=VARCHAR}
	,	#{stbNm, jdbcType=VARCHAR}
	,	sysdate
	,	#{sstepStatus, jdbcType=VARCHAR}
	,	#{scomment, jdbcType=VARCHAR}
	,	#{sbatchEndYn, jdbcType=VARCHAR}
	,	sysdate
	,	sysdate
)

	SELECT LASTVAL()

mapper.update:
UPDATE
	BIF.TB_BATCH_LOG A
	SET	
		A.DEND_DT = SYSDATE
		,	A.DTOTAL_TIME = age(SYSDATE, A.DSTART_DT)

		,	A.NCNT = #{ncnt, jdbcType=INTEGER}


		,	A.SSTEP_STATUS = #{sstepStatus, jdbcType=VARCHAR}


		,	A.SCOMMENT = #{scomment, jdbcType=VARCHAR}


		,	A.SBATCH_END_YN = #{sbatchEndYn, jdbcType=VARCHAR}

		,	A.DMODIFY_DT = sysdate

mapper.select:
SELECT A.NINPUT_SEQ , A.NPID , A.SIF_ID , A.SSYS_NM , A.STB_NM , A.DSTART_DT , A.DEND_DT , (DATE_PART('MINUTE',A.DTOTAL_TIME)||'분'||LPAD(DATE_PART('SECOND',A.DTOTAL_TIME),6,'0')||'초') AS DTOTAL_TIME , A.NCNT , A.SCOMMENT , A.SSTEP_STATUS , A.SBATCH_END_YN , A.DCREATE_DT , A.DMODIFY_DT , RNUM FROM ( SELECT A.NINPUT_SEQ , A.NPID , A.SIF_ID , A.SSYS_NM , A.STB_NM , A.DSTART_DT , A.DEND_DT , A.DTOTAL_TIME , A.NCNT , A.SCOMMENT , A.SSTEP_STATUS , A.SBATCH_END_YN , A.DCREATE_DT , A.DMODIFY_DT , ROWNUM RNUM FROM ( SELECT A.NINPUT_SEQ , A.NPID , A.SIF_ID , A.SSYS_NM , A.STB_NM , A.DSTART_DT , A.DEND_DT , A.DTOTAL_TIME , A.NCNT , A.SCOMMENT , A.SSTEP_STATUS , A.SBATCH_END_YN , A.DCREATE_DT , A.DMODIFY_DT FROM BIF.TB_BATCH_LOG A WHERE 1=1
AND A.SIF_ID = #{sifId, jdbcType=VARCHAR}
ORDER BY A.NINPUT_SEQ DESC ) A WHERE ROWNUM <= #{lastIndex} ) A WHERE RNUM >= #{firstIndex}

SELECT A.SIF_ID , A.SSYS_NM , A.STB_NM , A.DSTART_DT , A.DEND_DT , A.DTOTAL_TIME , A.NCNT , A.SCOMMENT , A.SSTEP_STATUS , A.SBATCH_END_YN , A.RNUM FROM ( SELECT A.SIF_ID , A.SSYS_NM , A.STB_NM , A.DSTART_DT , A.DEND_DT , A.DTOTAL_TIME , A.NCNT , A.SCOMMENT , A.SSTEP_STATUS , A.SBATCH_END_YN , ROWNUM RNUM FROM ( SELECT A.SIF_ID , A.SSYS_NM , A.STB_NM , A.DSTART_DT , A.DEND_DT , A.DTOTAL_TIME , A.NCNT , A.SCOMMENT , A.SSTEP_STATUS , NVL(A.SBATCH_END_YN, 'N') AS SBATCH_END_YN FROM BIF.TB_BATCH_LOG A WHERE 1=1
AND A.SIF_ID ILIKE '%' || #{sifId, jdbcType=VARCHAR} || '%'
AND NVL(A.SBATCH_END_YN, 'N') = #{sbatchEndYn, jdbcType=VARCHAR}
AND TO_CHAR(A.DSTART_DT, 'YYYY-MM-DD') >= #{searchBgnDe, jdbcType=TIMESTAMP}
AND TO_CHAR(A.DEND_DT, 'YYYY-MM-DD') <= #{searchEndDe, jdbcType=TIMESTAMP}
ORDER BY NVL(A.DMODIFY_DT, A.DCREATE_DT) DESC ) A WHERE ROWNUM <= #{lastIndex} ) A WHERE RNUM >= #{firstIndex}

SELECT count(1) totalCount 
FROM BIF.TB_BATCH_LOG A
WHERE 1=1

		AND A.SIF_ID ILIKE '%' || #{sifId, jdbcType=VARCHAR} || '%'


		AND NVL(A.SBATCH_END_YN, 'N') = #{sbatchEndYn, jdbcType=VARCHAR}


		AND TO_CHAR(A.DSTART_DT, 'YYYY-MM-DD') >=  #{searchBgnDe, jdbcType=TIMESTAMP}


		AND TO_CHAR(A.DEND_DT, 'YYYY-MM-DD') <=  #{searchEndDe, jdbcType=TIMESTAMP}
